
import { useUser } from '@/src/hooks/use-user';
import { useUserStore } from '@/src/store/user-store';
import { Avatar, UnstyledButton, Menu, LoadingOverlay } from '@mantine/core';
import { notifications } from '@mantine/notifications';
import { IconLogout } from '@tabler/icons-react';
import { redirect } from 'next/navigation';

interface UserDisplayProps {
    profile_pic?: string
    name: string
}

export function UserDisplay({ profile_pic, name }: UserDisplayProps) {
    const {
        logout
    } = useUser()

    const { clearData } = useUserStore()

    const { trigger, isMutating } = logout({
        successCallback: (success: boolean) => {
            if (!success) return
            clearData()
            redirect('/')
        },
        errorCallback: (error: Error) => {
            notifications.show({
                color: 'red',
                title: 'Logout failed',
                message: error.message || 'Something went wrong. Please try again.',
            })
        }
    })

    return (
        <>
            <LoadingOverlay
                visible={isMutating}
                zIndex={1000}
                overlayProps={{ fixed: true, blur: 2 }}
            />
            <Menu withArrow>
                <Menu.Target>
                    <UnstyledButton
                        style={{
                            padding: 'var(--mantine-spacing-md)',
                            color: 'var(--mantine-color-text)',
                            borderRadius: 'var(--mantine-radius-sm)',
                        }}
                    >
                        <Avatar src={profile_pic || "/empty_profile_img.png"} alt={name} />
                    </UnstyledButton>
                </Menu.Target>
                <Menu.Item
                    leftSection={<IconLogout size={14} />}
                    onClick={() => { trigger() }}
                >
                    Logout
                </Menu.Item>
            </Menu>
        </>
    )
}